import{_ as e,o,c as t,O as i}from"./chunks/framework.bdcb0ee1.js";const u=JSON.parse('{"title":"Emoticons","description":"","frontmatter":{},"headers":[],"relativePath":"administration/config/emoticons.md","filePath":"administration/config/emoticons.md","lastUpdated":1773166504000}'),a={name:"administration/config/emoticons.md"},s=i('<h1 id="emoticons" tabindex="-1">Emoticons <a class="header-anchor" href="#emoticons" aria-label="Permalink to &quot;Emoticons&quot;">​</a></h1><p>ForumSpark allows you to define custom emoticons that users can include in their posts using shortcodes.</p><p>You can access the <strong>Emoticons</strong> panel from the <strong>Board Config</strong> section in the Admin Control Panel.</p><h2 id="adding-a-new-emoticon" tabindex="-1">Adding a New Emoticon <a class="header-anchor" href="#adding-a-new-emoticon" aria-label="Permalink to &quot;Adding a New Emoticon&quot;">​</a></h2><p>To add a new emoticon, provide the following:</p><ul><li><strong>Text to replace</strong>: This is the shortcode users will type, such as <code>:wave:</code> or <code>:)</code>. When the post is rendered, this text will be replaced by the associated image.</li><li><strong>Image URL</strong>: The full URL to the image to use for the emoticon. This must be a valid image format (e.g. <code>.png</code>, <code>.gif</code>, <code>.jpg</code>).</li><li><strong>Display order</strong>: Determines where the emoticon appears in the selection list. Lower numbers appear first.</li><li><strong>Show in list</strong>: If enabled, the emoticon will appear in the emoticon picker UI. You can keep this off for hidden or rarely used emoticons.</li></ul><img width="1943" height="701" alt="image" src="https://github.com/user-attachments/assets/e7654ca2-a2a9-4e1d-9629-4430ffaa9481"><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>Emoticons are parsed after BBCode, so make sure your shortcodes don&#39;t interfere with any formatting tags.</li><li>Avoid using very large images. Aim for small icons (e.g. 16–32px square) for consistency.</li><li>You can upload emoticon images directly to your board using the <strong>File Manager</strong> in the Admin Control Panel. After uploading, copy the URL from the file list and use it in the <strong>Image URL</strong> field.</li></ul><p>Once saved, the new emoticon will be available for use across all posts, shoutbox and private messages.</p>',10),n=[s];function r(c,l,d,m,h,g){return o(),t("div",null,n)}const f=e(a,[["render",r]]);export{u as __pageData,f as default};
